cd /Users/ainchorsoc2a/.openclaw/workspace && python3 -c "
import json
from datetime import datetime, timezone, timedelta
try:
    with open('state/heartbeat-state.json') as f:
        s = json.load(f)
    lc = s.get('lastChecks',{})
    now = datetime.now(timezone.utc)
    # Parse timestamps - they're AEST in the file
    checks = {}
    for k,v in lc.items():
        if isinstance(v,str) and 'T' in v:
            try:
                dt = datetime.fromisoformat(v.replace('+1000','+10:00').replace('+1100','+11:00'))
                checks[k] = dt
            except:
                pass
    print('Last checks timestamps (UTC):')
    for k,v in sorted(checks.items()):
        age = now - v
        print(f'  {k}: {age.total_seconds()/60:.0f}m ago')
except Exception as e:
    print(f'Error: {e}')
"
